VALUES
  ('aboriginal-f29af906-moex-00099', 'aboriginal-f29af906', 'aboriginal-f29af906-moex-111-d3e6a6cd', 'sub-aboriginal-f29af906-05', NULL, 'essay', '甲名下有 A地，甲在該地上興建未辦保存登記之B 屋後，便僑居國外。
乙見 B屋地點良好卻無人居住，即以所有之意思，和平、公然、繼續占
有 B 屋達 21 年。今甲年老回國，發現乙占用 B 屋經營商店，遂訴請乙
返還 B屋，乙則執其已依時效取得 B屋之所有權、其得請求登記為 B屋
之所有人等語，以資抗辯。問誰之主張有理？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:01+00:00", "source_pdf_sha1": "0f3929faec04", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "610", "s": "0804", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法物權編概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "地政"}'::jsonb, NULL),
  ('aboriginal-f29af906-moex-00100', 'aboriginal-f29af906', 'aboriginal-f29af906-moex-111-d3e6a6cd', 'sub-aboriginal-f29af906-05', NULL, 'essay', '甲名下有 A 地、B 地以及 C 地，而 B 地和 C 地均須藉由 A 地與公路相
通聯。甲其後分別將 B地讓與乙、C地讓與丙，使得 B地、C地除通行
A地外，僅能通行周圍地即丁之D地至公路。今乙對甲主張通行權，甲
即要求乙支付償金，當丙向丁主張袋地通行權，丁旋拒絕之。問誰之主
張或抗辯有理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:01+00:00", "source_pdf_sha1": "0f3929faec04", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "610", "s": "0804", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法物權編概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "地政"}'::jsonb, NULL),
  ('aboriginal-f29af906-moex-00101', 'aboriginal-f29af906', 'aboriginal-f29af906-moex-111-d3e6a6cd', 'sub-aboriginal-f29af906-05', NULL, 'essay', '甲、乙、丙、丁、戊五人共有 A地，應有部分均等。甲、乙、丙三人同
意將 A地出借予庚，丁、戊二人同意將 A地出租於辛，而甲未得其他共
有人同意，便將其應有部分設定普通抵押權予壬，問上述出借、出租以
及設定抵押權行為之效力分別為何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:01+00:00", "source_pdf_sha1": "0f3929faec04", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "610", "s": "0804", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法物權編概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "地政"}'::jsonb, NULL),
  ('aboriginal-f29af906-moex-00102', 'aboriginal-f29af906', 'aboriginal-f29af906-moex-111-d3e6a6cd', 'sub-aboriginal-f29af906-05', NULL, 'essay', '甲有一輛新車，被乙竊取。二年後，乙透過經營中古車行之丙代為出售，
由善意之丁買得。其後，甲發現丁駕駛其失竊的汽車，遂向丁請求回復
其物。對此，丁提出甲已罹於法定除斥期間、甲非償還其支出之價金，
不得回復其物等抗辯。問誰之主張有理？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:01+00:00", "source_pdf_sha1": "0f3929faec04", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "610", "s": "0804", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法物權編概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "地政"}'::jsonb, NULL),
  ('aboriginal-f29af906-moex-00103', 'aboriginal-f29af906', 'aboriginal-f29af906-moex-111-6ed013db', 'sub-aboriginal-f29af906-11', NULL, 'single_choice', '依司法院釋字第499號解釋，修憲應循正當修憲程序為之，如有下列何種瑕疵，即不生其應有之效力？', '["重大瑕疵", "明顯瑕疵", "明顯錯誤瑕疵", "明顯重大瑕疵"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:01+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "610", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "地政"}'::jsonb, NULL),
  ('aboriginal-f29af906-moex-00104', 'aboriginal-f29af906', 'aboriginal-f29af906-moex-111-6ed013db', 'sub-aboriginal-f29af906-11', NULL, 'single_choice', '有關中華民國國防，下列敘述何者錯誤？', '["目的在於保衛國家安全，維護世界和平", "武力包含陸海空軍", "現役軍人得兼任文官", "保持政治中立"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:01+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "610", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "地政"}'::jsonb, NULL),
  ('aboriginal-f29af906-moex-00105', 'aboriginal-f29af906', 'aboriginal-f29af906-moex-111-6ed013db', 'sub-aboriginal-f29af906-11', NULL, 'single_choice', '依憲法規定及相關學理，關於軍事審判權，下列敘述何者最為正確？', '["憲法第9條明文保障非現役軍人不受軍事審判", "為維護軍紀，軍事法院判決應經國防部部長之核可", "憲法第9條明文規定現役軍人應受軍事審判", "法律不得規定僅軍事審判機關對軍人犯罪有專屬審判權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:01+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "610", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "地政"}'::jsonb, NULL),
  ('aboriginal-f29af906-moex-00106', 'aboriginal-f29af906', 'aboriginal-f29af906-moex-111-6ed013db', 'sub-aboriginal-f29af906-11', NULL, 'single_choice', '監獄檢閱受刑人書信時，不得有下列何種行為？', '["確認有無夾帶違禁品", "區分書信種類，斟酌個案情形，以判斷監獄長官能否閱讀書信之內容", "基於維護監獄紀律所必要而刪除書信部分內容，並保留書信全文影本，俟受刑人出獄時發還之", "對受刑人所撰寫文稿之內容，審查其題意是否正確或有無損害監獄信譽"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:01+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "610", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "地政"}'::jsonb, NULL),
  ('aboriginal-f29af906-moex-00107', 'aboriginal-f29af906', 'aboriginal-f29af906-moex-111-6ed013db', 'sub-aboriginal-f29af906-11', NULL, 'single_choice', '依照司法院釋字第422號解釋，耕地三七五減租條例第19條第1項第3款規定，出租人因收回耕 地，致承租人失其家庭生活依據者，耕地租約期滿時，出租人不得收回自耕。目的即在保障下列何種 基本權利？', '["生存權", "工作權", "財產權", "平等權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:01+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "610", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "地政"}'::jsonb, NULL),
  ('aboriginal-f29af906-moex-00108', 'aboriginal-f29af906', 'aboriginal-f29af906-moex-111-6ed013db', 'sub-aboriginal-f29af906-11', NULL, 'single_choice', '依司法院解釋意旨，退休人員再任私立學校職務且每月支領薪酬總額超過法定基本工資，停止領受月 退休金權利之規定，牴觸下列何者基本權利？', '["平等權", "工作權", "財產權", "生存權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:01+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "610", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "地政"}'::jsonb, NULL)
